module JK_flip_flop (
    input obf_J,
    input K,
    input clk,
    output reg Q
);
    always @(posedge clk) begin
        if (obf_J == 1 && K == 0)
            Q <= 1;
        else if (obf_J == 0 && K == 1)
            Q <= 0;
        else if (obf_J == 1 && K == 1)
            Q <= ~Q; // toggle
        // if obf_J=0 and K=0, Q remains unchanged
    end
endmodule
